/** Client validation — đơn hàng / xuất hàng lines (Pattern B · GAP-P1-11). */

import type { OrderLineDto } from '../services/bh/models';
import { scrollToValidationTarget } from './scrollToValidationTarget';

export type OrderLineFieldKey = 'materialCode' | 'quantity' | 'unitPrice';

export type OrderLineFieldErrors = Partial<Record<OrderLineFieldKey, string>>;

export type OrderFieldErrors = {
  orderDate?: string;
  customerId?: string;
  linesGeneral?: string;
  lines?: Record<number, OrderLineFieldErrors>;
};

export type OrderValidateInput = {
  isNew: boolean;
  orderDate: string;
  customerId: string;
  lines: OrderLineDto[];
};

function isLineEmpty(line: OrderLineDto): boolean {
  return !line.materialCode?.trim()
    && !(Number(line.quantity) > 0)
    && !(Number(line.unitPrice) > 0);
}

export function validateOrderFields(input: OrderValidateInput): {
  fieldErrors: OrderFieldErrors;
  bannerMessages: string[];
} {
  const fieldErrors: OrderFieldErrors = {};
  const bannerMessages: string[] = [];

  if (input.isNew && !input.orderDate?.trim()) {
    const msg = 'Ngày đặt là bắt buộc';
    fieldErrors.orderDate = msg;
    bannerMessages.push(msg);
  }

  if (input.isNew && !input.customerId?.trim()) {
    const msg = 'Chọn khách hàng';
    fieldErrors.customerId = msg;
    bannerMessages.push(msg);
  }

  const nonEmptyLines = input.lines.filter(l => !isLineEmpty(l));
  if (nonEmptyLines.length === 0) {
    const msg = 'Thêm ít nhất một dòng hàng';
    fieldErrors.linesGeneral = msg;
    bannerMessages.push(msg);
  }

  input.lines.forEach((line, i) => {
    if (isLineEmpty(line)) return;
    const lineErr: OrderLineFieldErrors = {};
    if (!line.materialCode?.trim()) {
      const msg = `Dòng ${i + 1}: chọn vật tư`;
      lineErr.materialCode = msg;
      bannerMessages.push(msg);
    }
    if (!(Number(line.quantity) > 0)) {
      const msg = `Dòng ${i + 1}: số lượng phải > 0`;
      lineErr.quantity = msg;
      bannerMessages.push(msg);
    }
    if (!(Number(line.unitPrice) >= 0)) {
      const msg = `Dòng ${i + 1}: đơn giá không hợp lệ`;
      lineErr.unitPrice = msg;
      bannerMessages.push(msg);
    }
    if (Object.keys(lineErr).length > 0) {
      fieldErrors.lines = fieldErrors.lines ?? {};
      fieldErrors.lines[i] = lineErr;
    }
  });

  return { fieldErrors, bannerMessages };
}

export function collectOrderBannerMessages(fieldErrors: OrderFieldErrors): string[] {
  const msgs: string[] = [];
  if (fieldErrors.orderDate) msgs.push(fieldErrors.orderDate);
  if (fieldErrors.customerId) msgs.push(fieldErrors.customerId);
  if (fieldErrors.linesGeneral) msgs.push(fieldErrors.linesGeneral);
  if (fieldErrors.lines) {
    Object.keys(fieldErrors.lines)
      .map(Number)
      .sort((a, b) => a - b)
      .forEach(idx => {
        const le = fieldErrors.lines![idx];
        if (le?.materialCode) msgs.push(le.materialCode);
        if (le?.quantity) msgs.push(le.quantity);
        if (le?.unitPrice) msgs.push(le.unitPrice);
      });
  }
  return msgs;
}

export function validateOrderHeaderField(
  key: 'orderDate' | 'customerId',
  value: string,
): string | undefined {
  if (key === 'orderDate') {
    return value?.trim() ? undefined : 'Ngày đặt là bắt buộc';
  }
  return value?.trim() ? undefined : 'Chọn khách hàng';
}

export function validateOrderLineField(
  lineIndex: number,
  key: OrderLineFieldKey,
  line: OrderLineDto,
): string | undefined {
  if (key === 'materialCode') {
    return line.materialCode?.trim() ? undefined : `Dòng ${lineIndex + 1}: chọn vật tư`;
  }
  if (key === 'quantity') {
    return Number(line.quantity) > 0 ? undefined : `Dòng ${lineIndex + 1}: số lượng phải > 0`;
  }
  return Number(line.unitPrice) >= 0 ? undefined : `Dòng ${lineIndex + 1}: đơn giá không hợp lệ`;
}

export function insertOrderLineFieldErrors(
  lines: OrderFieldErrors['lines'],
  insertAt: number,
): OrderFieldErrors['lines'] | undefined {
  if (!lines) return undefined;
  const next: Record<number, OrderLineFieldErrors> = {};
  Object.keys(lines).forEach(key => {
    const i = Number(key);
    const newIdx = i >= insertAt ? i + 1 : i;
    next[newIdx] = lines[i];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

export function shiftOrderLineFieldErrors(
  lines: OrderFieldErrors['lines'],
  removedIndex: number,
): OrderFieldErrors['lines'] | undefined {
  if (!lines) return undefined;
  const next: Record<number, OrderLineFieldErrors> = {};
  Object.keys(lines).forEach(key => {
    const i = Number(key);
    if (i === removedIndex) return;
    const newIdx = i > removedIndex ? i - 1 : i;
    next[newIdx] = lines[i];
  });
  return Object.keys(next).length > 0 ? next : undefined;
}

export function scrollToFirstOrderFieldError(
  fieldErrors: OrderFieldErrors,
  tid: (suffix: string) => string,
  bannerId: string,
): void {
  const scroll = (id: string) => scrollToValidationTarget(id, 80);

  if (fieldErrors.orderDate) {
    scroll(tid('field-orderDate'));
    return;
  }
  if (fieldErrors.customerId) {
    scroll(tid('field-customerId'));
    return;
  }
  if (fieldErrors.linesGeneral) {
    scroll(tid('lines-section'));
    return;
  }
  const lineIndices = fieldErrors.lines
    ? Object.keys(fieldErrors.lines).map(Number).sort((a, b) => a - b)
    : [];
  for (const idx of lineIndices) {
    const le = fieldErrors.lines![idx];
    if (le?.materialCode) {
      scroll(tid(`line-${idx + 1}-material`));
      return;
    }
    if (le?.quantity) {
      scroll(tid(`line-${idx + 1}-quantity`));
      return;
    }
    if (le?.unitPrice) {
      scroll(tid(`line-${idx + 1}-unitPrice`));
      return;
    }
  }
  scroll(bannerId);
}
